function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: number[][][] = new Array(n).fill(0).map(() => new Array<number>(0));

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (online[u]) {
            graph[u].push([v, cost]);
        }
    }

    // Use Dijkstra's algorithm to find the maximum minimum edge cost
    // We'll use a max-heap to prioritize paths with higher minimum edge cost
    // We'll store the minimum edge cost so far and the total cost so far
    // We'll also store the path's minimum edge cost

    // Priority queue: [minEdgeCost, totalCost, current node]
    const pq: [number, number, number][] = [[Number.MAX_VALUE, 0, 0]];
    const visited: Set<number> = new Set();

    while (pq.length > 0) {
        // Pop the path with the highest minimum edge cost
        pq.sort((a, b) => b[0] - a[0]);
        const [minEdge, totalCost, node] = pq.shift()!;

        if (node === n - 1) {
            return minEdge;
        }

        if (visited.has(node)) {
            continue;
        }

        visited.add(node);

        for (const [neighbor, cost] of graph[node]) {
            if (online[neighbor]) {
                const newTotalCost = totalCost + cost;
                const newMinEdge = Math.min(minEdge, cost);

                if (newTotalCost <= k) {
                    pq.push([newMinEdge, newTotalCost, neighbor]);
                }
            }
        }
    }

    return -1;
}

