public static long solve(long[][] edges, boolean[] online, long k) {
    int n = online.length;
    List<List<long[]>> graph = new ArrayList<>(n);
    for (int i = 0; i < n; i++) {
        graph.add(new ArrayList<>());
    }

    // Build the graph
    for (long[] edge : edges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        long cost = edge[2];
        if (online[u]) {
            graph.get(u).add(new long[]{v, cost});
        }
    }

    // Use a max-heap to prioritize paths with higher minimum edge cost
    // We'll store the minimum edge cost so far and the total cost so far
    // We'll also store the current node
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> {
        long aMin = a[0], bMin = b[0];
        return Long.compare(bMin, aMin);
    });
    pq.offer(new long[]{Long.MAX_VALUE, 0, 0});

    // Keep track of visited nodes
    boolean[] visited = new boolean[n];

    while (!pq.isEmpty()) {
        long[] current = pq.poll();
        long minEdge = current[0], totalCost = current[1], node = current[2];

        if (node == n - 1) {
            return minEdge;
        }

        if (visited[node]) {
            continue;
        }

        visited[node] = true;

        for (long[] neighbor : graph.get(node)) {
            int v = (int) neighbor[0];
            long cost = neighbor[1];
            if (online[v]) {
                long newTotalCost = totalCost + cost;
                long newMinEdge = Math.min(minEdge, cost);

                if (newTotalCost <= k) {
                    pq.offer(new long[]{newMinEdge, newTotalCost, v});
                }
            }
        }
    }

    return -1;
}
