public static long solve(long[][] edges, boolean[] online, long k) {
    int n = online.length;
    long[][] graph = new long[n][];

    // Build the graph
    for (int i = 0; i < n; i++) {
        graph[i] = new long[0];
    }

    for (long[] edge : edges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        long cost = edge[2];
        if (online[u]) {
            long[] neighbors = graph[u];
            long[] newNeighbors = new long[neighbors.length + 1];
            System.arraycopy(neighbors, 0, newNeighbors, 0, neighbors.length);
            newNeighbors[neighbors.length] = cost;
            graph[u] = newNeighbors;
        }
    }

    // Use a max-heap to prioritize paths with higher minimum edge cost
    // We'll use a priority queue: [minEdgeCost, totalCost, current node]
    java.util.PriorityQueue<long[]> pq = new java.util.PriorityQueue<>( 
        (a, b) -> Long.compare(b[0], a[0])
    );
